import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import './App.css';
import {
  bufferTurn,
  placeFood,
  stepSnake,
  type Direction,
  type Point,
  type SnakeSnapshot
} from './snake-engine';

const BOARD_SIZE = 14;
const STEP_MS = 140;
const INITIAL_SNAKE: Point[] = [
  { x: 6, y: 7 }, { x: 5, y: 7 }, { x: 4, y: 7 }
];

type GameState = SnakeSnapshot & {
  isRunning: boolean;
  terminal: 'none' | 'lost' | 'won';
};

function pointKey(point: Point): string {
  return point.x + ',' + point.y;
}

function directionFromKey(key: string): Direction | null {
  if (key === 'arrowup' || key === 'w') return 'UP';
  if (key === 'arrowdown' || key === 's') return 'DOWN';
  if (key === 'arrowleft' || key === 'a') return 'LEFT';
  if (key === 'arrowright' || key === 'd') return 'RIGHT';
  return null;
}

function initialGame(): GameState {
  const snake = INITIAL_SNAKE.map((point) => ({ ...point }));
  return {
    snake,
    direction: 'RIGHT',
    bufferedDirection: null,
    food: placeFood(snake, BOARD_SIZE),
    score: 0,
    isRunning: false,
    terminal: 'none'
  };
}

export default function App() {
  const gameRef = useRef<GameState>(initialGame());
  const [game, setGame] = useState<GameState>(gameRef.current);

  const commit = useCallback((next: GameState) => {
    gameRef.current = next;
    setGame(next);
  }, []);

  const resetGame = useCallback(() => commit(initialGame()), [commit]);

  useEffect(() => {
    const onKeyDown = (event: KeyboardEvent) => {
      const key = String(event.key || '').toLowerCase();
      const current = gameRef.current;

      if (key === ' ') {
        event.preventDefault();
        if (current.terminal === 'none') commit({ ...current, isRunning: !current.isRunning });
        return;
      }

      if (key === 'enter' && current.terminal !== 'none') {
        event.preventDefault();
        resetGame();
        return;
      }

      const requested = directionFromKey(key);
      if (!requested) return;
      event.preventDefault();
      const bufferedDirection = bufferTurn(
        current.direction,
        current.bufferedDirection,
        requested
      );
      if (bufferedDirection !== current.bufferedDirection) {
        commit({ ...current, bufferedDirection });
      }
    };

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [commit, resetGame]);

  useEffect(() => {
    if (!game.isRunning || game.terminal !== 'none') return undefined;

    const timerId = window.setInterval(() => {
      const current = gameRef.current;
      if (!current.isRunning || current.terminal !== 'none') return;
      const result = stepSnake(current, BOARD_SIZE);
      const terminal = result.outcome === 'lost'
        ? 'lost'
        : result.outcome === 'won'
          ? 'won'
          : 'none';
      commit({
        snake: result.snake,
        direction: result.direction,
        bufferedDirection: result.bufferedDirection,
        food: result.food,
        score: result.score,
        terminal,
        isRunning: terminal === 'none'
      });
    }, STEP_MS);

    return () => window.clearInterval(timerId);
  }, [game.isRunning, game.terminal, commit]);

  const snakeSet = useMemo(() => new Set(game.snake.map(pointKey)), [game.snake]);
  const foodKey = game.food === null ? null : pointKey(game.food);
  const status = game.terminal === 'won'
    ? 'You win'
    : game.terminal === 'lost'
      ? 'Game over'
      : game.isRunning ? 'Running' : 'Paused';

  return (
    <main className="page">
      <section className="card">
        <h1>Snake (Grid + Collision)</h1>
        <p className="subtitle">Build a keyboard-controlled snake game with safe buffered turns and an explicit full-board win.</p>
        <div className="statusRow">
          <span className="pill">Score: {game.score}</span>
          <span className="pill">Length: {game.snake.length}</span>
          <span className={game.terminal === 'lost' ? 'pill pill--danger' : 'pill'}>{status}</span>
        </div>
        <div className="actions">
          <button type="button" className="ghost" onClick={() => {
            const current = gameRef.current;
            if (current.terminal === 'none') commit({ ...current, isRunning: !current.isRunning });
          }}>{game.isRunning ? 'Pause' : 'Start'}</button>
          <button type="button" className="ghost" onClick={resetGame}>Reset</button>
        </div>
        <div className="board" role="grid" aria-label="snake board" style={{ gridTemplateColumns: 'repeat(' + BOARD_SIZE + ', minmax(0, 1fr))' }}>
          {Array.from({ length: BOARD_SIZE * BOARD_SIZE }, (_, index) => {
            const x = index % BOARD_SIZE;
            const y = Math.floor(index / BOARD_SIZE);
            const key = x + ',' + y;
            const isHead = game.snake[0]?.x === x && game.snake[0]?.y === y;
            const isBody = snakeSet.has(key);
            const isFood = key === foodKey;
            return <div key={key} className={['cell', isBody ? 'cell--snake' : '', isHead ? 'cell--head' : '', isFood ? 'cell--food' : ''].join(' ').trim()} aria-label={isHead ? 'snake head' : isFood ? 'food' : 'empty cell'} />;
          })}
        </div>
        <p className="hint">Use Arrow keys or WASD to move. Space pauses, Enter resets after game over or a win.</p>
      </section>
    </main>
  );
}

